  if (lowerText.match(/3\s*uhr|3\s*am|nacht|night|schlafen|sleep|wach|awake|dunkel|dark/i)) {
    timeContext = "night";
  } else if (lowerText.match(/morgen|morning|aufstehen|wake up|kaffee|coffee|fr\u00FCh|early/i)) {
    timeContext = "morning";
  }
