            const uniqueHashtags2 = [...new Set(hashtags)];
            const body2 = bodyLines2.join(`
`).trim();
            const hashtagLine = uniqueHashtags2.join(" ").trim();
            return hashtagLine ? `${body2}
${hashtagLine}`.trim() : body2;
